def get_fallback_tracks(mood, limit=5):
    """Returns a stable curated selection of fallback tracks for a given mood."""
    base = FALLBACK_DB.get(mood, FALLBACK_DB['Chill'])

    # Format them exactly like the spotify.py output
    results = []
    for t in base[:limit]:
        results.append({
            'title': t['name'],
            'name': t['name'],
            'artist': t['artist'],
            'albumArt': t['album_art'],
            'album_art': t['album_art'],
            'preview_url': t['preview_url'],
            'previewUrl': t['preview_url'],
            'spotifyUrl': t['spotify_url'],
            'spotify_url': t['spotify_url']
        })
    return results
